## Deterministic ``packages/<tool>.nim`` emitter for the M66
## catalog harvester.
##
## Wraps ``packages_schema.serializeAsCode`` (M63) with a per-file
## header carrying the bucket reference and a stable header comment.
## Re-running the harvester on the same inputs produces byte-
## identical output (the "idempotent harvest" gate).
##
## Header shape (kept terse — no timestamp / no commit-SHA so the
## file diff is empty across re-runs against an unchanged bucket;
## the bucket + app + version list IS deterministic for a given
## input):
##
## .. code-block:: nim
##    ## Auto-generated by tools/catalog-harvester. DO NOT EDIT.
##    ## Harvested from bucket: scoopinstaller/main
##    ## Versions (newest-first): 21.0.5, 17.0.13, 11.0.25
##
##    import ../packages_schema
##    export packages_schema
##
##    let <tool>Catalog* = @[
##      VersionedProvisioning(...),
##      ...
##    ]

import std/strutils
import repro_dsl_stdlib/packages_schema

const Header = "## Auto-generated by tools/catalog-harvester. DO NOT EDIT.\n"

proc indent(blockText: string; spaces: int): string =
  let pad = " ".repeat(spaces)
  result = newStringOfCap(blockText.len + 32)
  var lineStart = true
  for ch in blockText:
    if lineStart and ch != '\n':
      result.add(pad)
      lineStart = false
    result.add(ch)
    if ch == '\n':
      lineStart = true

proc patchEmptyEnv(src: string): string =
  ## Workaround for an edge case in M63's ``serializeAsCode``: an
  ## empty ``env`` table is rendered as ``env: {}.toTable()`` which
  ## fails to type-check because ``{}`` has type ``set[empty]``. We
  ## rewrite that literal to ``initTable[string, string]()`` so the
  ## emitted file is round-trippable through ``nim check`` even when
  ## the manifest had no ``env_set`` block. (The non-empty case
  ## ``{"K": "V"}.toTable()`` continues to type-check; this patch is
  ## a string substitution targeting only the empty form.)
  src.replace("env: {}.toTable()",
              "env: initTable[string, string]()")

proc emitCatalogFile*(toolName: string;
                      bucketSpec: string;
                      catalog: openArray[VersionedProvisioning]):
    string =
  ## Render the full ``packages/<tool>.nim`` body. The catalog is
  ## emitted in the order it was passed (the harvester is responsible
  ## for sorting newest-first BEFORE calling this proc).
  result = Header
  result.add("## Harvested from bucket: " & bucketSpec & "\n")
  if catalog.len > 0:
    var versions = newSeq[string](catalog.len)
    for i, vp in catalog: versions[i] = vp.version
    result.add("## Versions (newest-first): " & versions.join(", ") & "\n")
  result.add("\n")
  result.add("import std/tables\n")
  result.add("import repro_dsl_stdlib/packages_schema\n")
  result.add("export packages_schema\n")
  result.add("\n")
  result.add("let " & toolName & "Catalog* = @[\n")
  for i, vp in catalog:
    let body = patchEmptyEnv(serializeAsCode(vp))
    result.add(indent(body, 2))
    if i + 1 < catalog.len:
      result.add(",")
    result.add("\n")
  result.add("]\n")
